<template>
  <section class="section">
    <div class="container">
      <base-modal :show="!!error" color="is-danger" title="Data Loading Error" @close="handleError">
        {{ error }}
      </base-modal>
      <div v-if="isLoading">
        <base-spinner></base-spinner>
      </div>
      <contract-list class="mb-6" v-if="hasPendingContracts" :contracts="pendingContracts" title="Contracts with Pending Payments" :update="true" :extend="false"></contract-list>
      <contract-list class="mb-6" v-if="hasActiveContracts" :contracts="activeContracts" title="Active Contracts" :update="false" :extend="true"></contract-list>
      <contract-list v-if="hasClosedContracts" :contracts="closedContracts" title="Closed Contracts" :update="false" :extend="false"></contract-list>
      <div class="card" v-if="!hasContracts">
        <div class="card-header">
          <p class="card-header-title">
            No Contracts Available
          </p>
        </div>
        <div class="card-content content">
          <p>Sorry, we could not find any contracts associated with your account.</p>
        </div>
      </div>
    </div>
  </section>
</template>

<script>
import BaseSpinner from "@/components/ui/BaseSpinner";
import BaseModal from "@/components/ui/BaseModal";
import ContractList from "@/components/contracts/ContractList";

export default {
  name: "UserContracts",
  components: {
    BaseSpinner,
    BaseModal,
    ContractList
  },
  computed: {
    hasContracts() {
      return this.$store.getters['contracts/hasContracts'];
    },
    contracts() {
      return this.$store.getters['contracts/contracts'];
    },
    hasPendingContracts() {
      return this.$store.getters['contracts/hasPendingContracts'];
    },
    hasActiveContracts() {
      return this.$store.getters['contracts/hasActiveContracts'];
    },
    hasClosedContracts() {
      return this.$store.getters['contracts/hasClosedContracts'];
    },
    pendingContracts() {
      return this.$store.getters['contracts/pendingContracts'];
    },
    activeContracts() {
      return this.$store.getters['contracts/activeContracts'];
    },
    closedContracts() {
      return this.$store.getters['contracts/closedContracts'];
    }
  },
  data() {
    return {
      isLoading: false,
      error: null
    };
  },
  methods: {
    async loadContracts(force = false) {
      this.isLoading = true;
      try {
        await this.$store.dispatch('contracts/loadContracts', {forceRefresh: force});
      } catch (error) {
        this.error = error.message || 'Could not load contract data';
      }
      this.isLoading = false;
    },
    handleError() {
      this.error = null;
    }
  },
  created() {
    this.loadContracts(false);
  }
}
</script>
