<template>
  <section>
    <base-modal :show="!!error" color="is-danger" title="Error" @close="handleError">{{ error }}</base-modal>
    <base-modal :show="success" color="is-success" title="Payments Refreshed" @close="handleSuccess">
      Payment data has been refreshed. If the system recognized any pending payments, the corresponding aircraft
      will have automatically been leased out to the indicated target account.
    </base-modal>
    <base-modal :show="details.show" color="is-info" title="Maintenance Information" @close="handleDetails">
      <p class="mb-2">for contract #{{ details.id }}, aircraft {{ details.reg }} {{ details.model }}</p>
      <p class="mb-2" v-if="(details.inspectionRate > 0.0) && !details.inspectionRefund">
        You are eligible for a refund of {{ details.inspectionRate * 100 }}% of the cost of your first 100 hours
        inspection.
      </p>
      <p class="mb-2" v-else-if="(details.inspectionRate > 0.0) && details.inspectionRefund">
        {{ details.inspectionRate * 100 }}% of the cost of your first 100 hours inspection have already been refunded
        to you.
      </p>
      <p class="mb-2" v-else>
        At the moment of lease, the aircraft had less than 10 hours of hobbs time after its last 100 hours inspection.
        You are therefore not eligible for any refund on 100 hours inspection cost.
      </p>
      <p v-if="!details.ac_intact && !details.repairRefund">
        You are eligible to a refund of your first random damage repair, as the aircraft was in need of repair upon
        start of the leasing contract.
      </p>
      <p v-else-if="!details.ac_intact && details.repairRefund">
        Your first random damage repair has already been refunded to you, as the aircraft was in need of repair upon
        start of the leasing contract.
      </p>
      <p v-else>
        At the moment of lease, the aircraft was not in need of repair. You are therefore not eligible for any refund
        on random repair cost.
      </p>
    </base-modal>
    <div v-if="isLoading">
      <base-spinner></base-spinner>
    </div>

    <div class="card" :class="classes">
      <div class="card-header">
        <p class="card-header-title">
          {{ title }}
        </p>
      </div>
      <div class="card-content content">
        <table class="table is-striped is-hoverable is-fullwidth">
          <thead>
          <tr>
            <th>Id</th>
            <th>Aircraft</th>
            <th>Model</th>
            <th>Leasing Rate</th>
            <th>Leased To</th>
            <th>Start</th>
            <th>End</th>
            <th>Paid Until</th>
          </tr>
          <tr v-for="contract in contracts" :key="contract.id" @click="showDetails(contract.id)">
            <td>{{ contract.id }}</td>
            <td>{{ contract.ac_reg }}</td>
            <td>{{ contract.ac_type }}</td>
            <td>{{ 'v$' + contract.rate.toLocaleString('en-US', {maximumFractionDigits: 0}) }}</td>
            <td>{{ contract.target_name }}</td>
            <td>{{ contract.start_date }}</td>
            <td>{{ contract.end_date }}</td>
            <td>{{ contract.paid_until }}</td>
          </tr>
          </thead>
        </table>
        <div v-if="update || extend">
          <p v-if="update">
            To activate your pending leasing contracts, please issue the corresponding payment from your personal
            account or the group account the aircraft shall be leased to (cf. &ldquo;Lease To&rdquo; in the table above)
            to the group account <span class="has-text-weight-semibold has-text-primary">Stormrose</span>. Please note:
          </p>
          <p v-if="extend">
            To extend an active leasing contract, simply send another monthly payment from your personal account or the
            group account the aircraft is leased to (cf. &ldquo;Lease To&rdquo; in the table above) to the group account
            <span class="has-text-weight-semibold has-text-primary">Stormrose</span>. Please note:
          </p>
          <ul>
            <li>All payments have to be made to the <span class="has-text-weight-semibold has-text-primary">Stormrose</span> group account</li>
            <li>Do not bundle or split payments &ndash; our automated system will look for one payment per leasing contract and month.</li>
            <li>Do not forget to put the aircraft registration into the comment field when sending a payment.</li>
          </ul>
          <button class="button is-primary is-outlined" @click="refreshPayments">
            <span class="icon is-small"><svg-icon type="mdi" :path="refreshIcon">&nbsp;</svg-icon></span>
            <span>Refresh Payment Status</span>
          </button>
        </div>
      </div>
    </div>
  </section>
</template>

<script>
import BaseSpinner from "@/components/ui/BaseSpinner";
import BaseModal from "@/components/ui/BaseModal";
import SvgIcon from '@jamescoyle/vue-icon';
import {mdiRefresh} from '@mdi/js';

export default {
  name: "ContractList",
  components: {
    BaseSpinner,
    BaseModal,
    SvgIcon
  },
  computed: {
    refreshIcon() {
      return mdiRefresh;
    }
  },
  data() {
    return {
      isLoading: false,
      error: null,
      success: false,
      details: {
        show: false,
        id: null,
        reg: null,
        model: null,
        inspectionRate: 0.0,
        inspectionRefund: false,
        ac_intact: true,
        repairRefund: false
      }
    }
  },
  props: {
    title: {
      type: String,
      required: true
    },
    update: {
      type: Boolean,
      required: false,
      default: false
    },
    extend: {
      type: Boolean,
      required: false,
      default: false
    },
    contracts: {
      type: Array,
      required: true
    },
    classes: {
      type: String,
      required: false,
      default: ''
    }
  },
  methods: {
    handleError() {
      this.error = null;
    },
    handleSuccess() {
      this.success = false;
    },
    handleDetails() {
      this.details.show = false;
    },
    showDetails(id) {
      const contract = this.contracts.find(c => c.id === id);
      if (!contract) {
        return;
      }
      this.details.id = contract.id;
      this.details.reg = contract.ac_reg;
      this.details.model = contract.ac_type;
      this.details.inspectionRate = contract.inspection_prorate;
      this.details.inspectionRefund = contract.inspection_refund;
      this.details.ac_intact = contract.ac_intact;
      this.details.repairRefund = contract.repair_refund;
      this.details.show = true;
    },
    async refreshPayments() {
      this.isLoading = true;
      try {
        await this.$store.dispatch('contracts/refreshPayments');
        this.success = true;
      } catch (error) {
        this.error = error.message || 'Could not refresh payment data';
      }
      this.isLoading = false;
    },
  }
}
</script>
